// === API contract ===
// POST /payments
// Headers: Idempotency-Key: <client-generated UUID, reused on retries>
// Body: { customerId, amountMinor, currency, source }
// 201/200 -> { paymentId, status }  (same key => same response, no double charge)

// === Schema (PostgreSQL) ===
// idempotency_keys(key PK, request_hash, payment_id, response_json, status, created_at)
// payments(id PK, customer_id, amount_minor, currency, status, psp_ref, created_at)
// ledger_entries(id PK, txn_id, account, direction CHECK(direction IN('DEBIT','CREDIT')),
//                amount_minor, currency, created_at)  -- append-only, sum per txn_id = 0
// outbox(id PK, payment_id, type, payload, published BOOLEAN DEFAULT false)

async function createPayment(req, deps) {
  const { db, psp } = deps;
  const idempotencyKey = req.headers['idempotency-key'];
  if (!idempotencyKey) return { status: 400, body: { error: 'Idempotency-Key required' } };

  const fingerprint = hash(JSON.stringify(req.body)); // detect key reuse on a different body

  return db.tx(async (t) => {
    // 1) Claim the key. Unique PK makes concurrent duplicates serialize to one winner.
    const claimed = await t.query(
      `INSERT INTO idempotency_keys(key, request_hash, status)
       VALUES ($1, $2, 'PENDING')
       ON CONFLICT (key) DO NOTHING
       RETURNING key`,
      [idempotencyKey, fingerprint]
    );

    if (claimed.rowCount === 0) {
      // Key already exists: a duplicate retry. Return the stored outcome.
      const prior = await t.one(`SELECT * FROM idempotency_keys WHERE key=$1`, [idempotencyKey]);
      if (prior.request_hash !== fingerprint)
        return { status: 422, body: { error: 'Idempotency-Key reused with a different request' } };
      if (prior.status === 'COMPLETED')
        return { status: 200, body: JSON.parse(prior.response_json) };
      // Still processing elsewhere; tell the client to retry the read.
      return { status: 409, body: { error: 'Request in progress', paymentId: prior.payment_id } };
    }

    // 2) We won the claim. Create the payment intent (PENDING).
    const payment = await t.one(
      `INSERT INTO payments(id, customer_id, amount_minor, currency, status)
       VALUES (gen_random_uuid(), $1, $2, $3, 'PENDING') RETURNING *`,
      [req.body.customerId, req.body.amountMinor, req.body.currency]
    );

    // 3) Write the outbox row in the SAME transaction (transactional outbox => no lost capture).
    await t.query(
      `INSERT INTO outbox(payment_id, type, payload)
       VALUES ($1, 'CAPTURE_REQUESTED', $2)`,
      [payment.id, JSON.stringify({ idempotencyKey })]
    );

    await t.query(`UPDATE idempotency_keys SET payment_id=$1 WHERE key=$2`, [payment.id, idempotencyKey]);

    // Synchronous part returns fast; capture happens in the worker below.
    return { status: 202, body: { paymentId: payment.id, status: 'PENDING' } };
  });
}

// === Async worker: drains outbox, calls PSP exactly-once, posts to ledger ===
async function captureWorker(deps) {
  const { db, psp } = deps;
  const jobs = await db.query(
    `SELECT * FROM outbox WHERE published=false AND type='CAPTURE_REQUESTED'
     ORDER BY id FOR UPDATE SKIP LOCKED LIMIT 50`
  );
  for (const job of jobs.rows) {
    const { idempotencyKey } = JSON.parse(job.payload);
    const payment = await db.one(`SELECT * FROM payments WHERE id=$1`, [job.payment_id]);
    if (payment.status !== 'PENDING') { await markPublished(db, job.id); continue; }

    // PSP idempotency: passing OUR key means a retried PSP call never charges twice.
    const result = await psp.charge({
      idempotencyKey,
      amount: payment.amount_minor,
      currency: payment.currency,
      customer: payment.customer_id
    });

    await db.tx(async (t) => {
      if (result.status === 'succeeded') {
        await t.query(`UPDATE payments SET status='CAPTURED', psp_ref=$1 WHERE id=$2`,
          [result.id, payment.id]);
        // Double-entry: debit customer receivable, credit platform cash. Balanced => sum 0.
        const txnId = randomUUID();
        await t.query(
          `INSERT INTO ledger_entries(txn_id, account, direction, amount_minor, currency) VALUES
           ($1,'customer:'||$2,'DEBIT',$3,$4),
           ($1,'platform:cash','CREDIT',$3,$4)`,
          [txnId, payment.customer_id, payment.amount_minor, payment.currency]
        );
        await t.query(
          `UPDATE idempotency_keys SET status='COMPLETED', response_json=$1 WHERE payment_id=$2`,
          [JSON.stringify({ paymentId: payment.id, status: 'CAPTURED' }), payment.id]
        );
      } else {
        await t.query(`UPDATE payments SET status='FAILED' WHERE id=$1`, [payment.id]);
        await t.query(
          `UPDATE idempotency_keys SET status='COMPLETED', response_json=$1 WHERE payment_id=$2`,
          [JSON.stringify({ paymentId: payment.id, status: 'FAILED' }), payment.id]
        );
      }
      await t.query(`UPDATE outbox SET published=true WHERE id=$1`, [job.id]);
    });
  }
}

