// Solution: move the transactional method to its own bean so the call crosses the proxy boundary.

@Service
public class OrderService {
    private final OrderProcessor processor; // separate bean => proxied call

    public OrderService(OrderProcessor processor) {
        this.processor = processor;
    }

    public BatchResult batchProcess(List<OrderDto> dtos) {
        int saved = 0, failed = 0;
        for (OrderDto dto : dtos) {
            try {
                processor.saveOrder(dto); // goes THROUGH the proxy -> @Transactional honored
                saved++;
            } catch (RuntimeException ex) {
                // This order's own transaction rolled back; continue with the rest.
                failed++;
            }
        }
        return new BatchResult(saved, failed);
    }
}

@Service
public class OrderProcessor {
    private final OrderRepository repo;

    public OrderProcessor(OrderRepository repo) {
        this.repo = repo;
    }

    // REQUIRES_NEW => each order is an independent transaction; one failure rolls back
    // only that order, leaving previously committed orders intact.
    @Transactional(propagation = Propagation.REQUIRES_NEW, rollbackFor = Exception.class)
    public void saveOrder(OrderDto dto) {
        Order order = new Order(dto);
        repo.save(order);
        if (dto.getAmount() < 0) {
            throw new IllegalArgumentException("negative amount"); // now actually rolls back this order
        }
    }
}

