// enable.auto.commit = false; we commit manually after durable processing.
Properties props = new Properties();
props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false);
props.put(ConsumerConfig.ISOLATION_LEVEL_CONFIG, "read_committed");

try (KafkaConsumer<String, OrderEvent> consumer = new KafkaConsumer<>(props)) {
    consumer.subscribe(List.of("orders"));
    while (running) {
        ConsumerRecords<String, OrderEvent> records = consumer.poll(Duration.ofMillis(500));
        for (TopicPartition tp : records.partitions()) {
            List<ConsumerRecord<String, OrderEvent>> partitionRecords = records.records(tp);
            for (ConsumerRecord<String, OrderEvent> rec : partitionRecords) {
                // Idempotent write: dedup on (topic, partition, offset) inside one DB txn.
                // INSERT ... ON CONFLICT DO NOTHING makes reprocessing a no-op.
                processIdempotently(rec);
            }
            // Commit ONLY after the side effects for this partition are durable.
            long lastOffset = partitionRecords.get(partitionRecords.size() - 1).offset();
            consumer.commitSync(Map.of(tp, new OffsetAndMetadata(lastOffset + 1)));
        }
    }
}

void processIdempotently(ConsumerRecord<String, OrderEvent> rec) {
    // single DB transaction
    jdbc.update("""
        INSERT INTO processed_offsets(topic, partition, \"offset\")
        VALUES (?, ?, ?)
        ON CONFLICT (topic, partition, \"offset\") DO NOTHING
        """, rec.topic(), rec.partition(), rec.offset());
    // The dedup insert + the business write share one transaction; if the insert was a
    // no-op (duplicate), guard the business write so it isn't applied twice.
    int inserted = /* rows affected by the insert above */ 1;
    if (inserted == 1) {
        applyBusinessEffect(rec.value()); // e.g. upsert order; itself keyed by order id
    }
}

import Redis from 'ioredis';
const redis = new Redis();
const inFlight = new Map<string, Promise<any>>(); // per-process request coalescing

async function getCached<T>(
  key: string,
  ttlMs: number,
  earlyMs: number,                 // refresh window before physical expiry
  compute: () => Promise<T>
): Promise<T> {
  // (1) coalesce concurrent callers in THIS process
  if (inFlight.has(key)) return inFlight.get(key)!;

  const run = (async () => {
    const raw = await redis.get(key);
    if (raw) {
      const { value, logicalExpiry } = JSON.parse(raw);
      // (3) probabilistic early recompute: as we approach expiry, one caller refreshes
      const now = Date.now();
      const shouldRefresh = now > logicalExpiry - earlyMs && Math.random() < 0.1;
      if (!shouldRefresh) return value as T;
      // fall through to try refreshing while still serving 'value' if we lose the lock
      const refreshed = await tryRecompute(key, ttlMs, compute);
      return (refreshed ?? value) as T;
    }
    // hard miss: must recompute under a lock
    return (await tryRecompute(key, ttlMs, compute)) as T;
  })();

  inFlight.set(key, run);
  try { return await run; } finally { inFlight.delete(key); }
}

async function tryRecompute<T>(key: string, ttlMs: number, compute: () => Promise<T>): Promise<T | null> {
  const lockKey = `lock:${key}`;
  // (2) only the lock winner recomputes
  const won = await redis.set(lockKey, '1', 'PX', 5000, 'NX');
  if (!won) {
    // someone else is recomputing: brief wait, then read whatever they wrote
    await new Promise(r => setTimeout(r, 50));
    const raw = await redis.get(key);
    return raw ? (JSON.parse(raw).value as T) : null;
  }
  try {
    const value = await compute();
    const payload = JSON.stringify({ value, logicalExpiry: Date.now() + ttlMs });
    // physical TTL slightly longer than logical so early-refresh has room to work
    await redis.set(key, payload, 'PX', ttlMs + 2000);
    return value;
  } finally {
    await redis.del(lockKey);
  }
}

// Broken: locks in transfer-direction order -> two opposite transfers deadlock.
// void transfer(long from, long to, long amt) {
//   lock(from); lock(to);   // A: lock(1),lock(2)   B: lock(2),lock(1)  => cycle
// }

// Fix: always lock accounts in a fixed global order (ascending id).
@Transactional
public void transfer(long from, long to, long amountMinor) {
    long firstId  = Math.min(from, to);
    long secondId = Math.max(from, to);

    // Acquire row locks deterministically; no two transactions can form a cycle.
    Account first  = jdbc.queryForObject(
        "SELECT * FROM accounts WHERE id = ? FOR UPDATE", accountMapper, firstId);
    Account second = jdbc.queryForObject(
        "SELECT * FROM accounts WHERE id = ? FOR UPDATE", accountMapper, secondId);

    Account src = (from == firstId) ? first : second;
    Account dst = (to   == firstId) ? first : second;

    if (src.balanceMinor() < amountMinor)
        throw new InsufficientFundsException(from);

    jdbc.update("UPDATE accounts SET balance_minor = balance_minor - ? WHERE id = ?", amountMinor, from);
    jdbc.update("UPDATE accounts SET balance_minor = balance_minor + ? WHERE id = ?", amountMinor, to);
}

// Bounded retry wrapper for residual deadlocks (e.g. PostgreSQL SQLSTATE 40P01).
public void transferWithRetry(long from, long to, long amt) {
    int attempts = 0;
    while (true) {
        try { transfer(from, to, amt); return; }
        catch (DeadlockLoserDataAccessException ex) {
            if (++attempts >= 3) throw ex;
            try { Thread.sleep(20L * attempts); } catch (InterruptedException ignored) {}
        }
    }
}

// Access token: signed JWT, 10-min expiry, sent in Authorization header.
// Refresh token: random opaque value, hashed in DB, rotated each use, in HttpOnly cookie.

function issueAccessToken(user) {
  return jwt.sign(
    { sub: user.id, roles: user.roles },
    PRIVATE_KEY,
    { algorithm: 'RS256', expiresIn: '10m', jwtid: randomUUID() }
  );
}

// POST /auth/refresh  (refresh token arrives via HttpOnly cookie)
async function refresh(req, res) {
  const presented = req.cookies['refresh_token'];
  const hash = sha256(presented);
  const record = await db.findRefreshToken(hash);

  // Reuse / theft detection: token unknown or already rotated => nuke the family.
  if (!record || record.rotated) {
    if (record) await db.revokeFamily(record.familyId); // someone is replaying an old token
    return res.status(401).json({ error: 'invalid refresh token' });
  }
  if (record.expiresAt < Date.now()) {
    return res.status(401).json({ error: 'refresh token expired' });
  }

  // Rotate: mark current as rotated, mint a NEW refresh token in the same family.
  await db.markRotated(record.id);
  const newRefresh = randomUUID() + randomUUID();
  await db.saveRefreshToken({
    hash: sha256(newRefresh),
    familyId: record.familyId,
    userId: record.userId,
    expiresAt: Date.now() + 14 * 24 * 3600 * 1000,
    rotated: false,
  });

  const user = await db.findUser(record.userId);
  res.cookie('refresh_token', newRefresh, {
    httpOnly: true, secure: true, sameSite: 'strict', path: '/auth/refresh',
  });
  return res.json({ accessToken: issueAccessToken(user) }); // kept in memory by the client
}

// Logout: revoke the whole family server-side.
async function logout(req, res) {
  const record = await db.findRefreshToken(sha256(req.cookies['refresh_token']));
  if (record) await db.revokeFamily(record.familyId);
  res.clearCookie('refresh_token', { path: '/auth/refresh' });
  res.status(204).end();
}

// Orchestration-based saga. The orchestrator drives steps and compensations.
// Each command/event carries the sagaId for idempotency and correlation.

type Step = {
  name: string;
  invoke: (ctx: SagaCtx) => Promise<void>;      // forward action (idempotent)
  compensate: (ctx: SagaCtx) => Promise<void>;  // semantic undo (idempotent, retryable)
};

const steps: Step[] = [
  {
    name: 'createOrder',
    invoke: (c) => orderSvc.create({ sagaId: c.sagaId, order: c.order }),       // PENDING
    compensate: (c) => orderSvc.cancel({ sagaId: c.sagaId }),
  },
  {
    name: 'reserveStock',
    invoke: (c) => inventorySvc.reserve({ sagaId: c.sagaId, items: c.order.items }),
    compensate: (c) => inventorySvc.release({ sagaId: c.sagaId }),
  },
  {
    name: 'capturePayment',
    invoke: (c) => paymentSvc.capture({ sagaId: c.sagaId, amount: c.order.total }),
    compensate: (c) => paymentSvc.refund({ sagaId: c.sagaId }),
  },
];

async function runSaga(ctx: SagaCtx) {
  const completed: Step[] = [];
  await sagaStore.save(ctx.sagaId, { status: 'RUNNING', stepIndex: 0 });
  try {
    for (let i = 0; i < steps.length; i++) {
      await sagaStore.save(ctx.sagaId, { status: 'RUNNING', stepIndex: i });
      await withRetry(() => steps[i].invoke(ctx)); // forward step, retried on transient error
      completed.push(steps[i]);
    }
    await orderSvc.confirm({ sagaId: ctx.sagaId });
    await sagaStore.save(ctx.sagaId, { status: 'COMPLETED' });
  } catch (err) {
    // Compensate completed steps in REVERSE order; compensations are retried until they succeed.
    await sagaStore.save(ctx.sagaId, { status: 'COMPENSATING' });
    for (const step of completed.reverse()) {
      await withRetry(() => step.compensate(ctx)); // must eventually succeed
    }
    await sagaStore.save(ctx.sagaId, { status: 'COMPENSATED' });
    throw err;
  }
}

async function withRetry(fn: () => Promise<void>, max = 5) {
  for (let attempt = 1; ; attempt++) {
    try { return await fn(); }
    catch (e) { if (attempt >= max) throw e; await sleep(100 * attempt); }
  }
}

// On orchestrator restart: load sagas in RUNNING/COMPENSATING from sagaStore and resume.

// WRITE side: normalized aggregate, validates invariants, emits events. No query concerns.
class PlaceOrderHandler {
  constructor(private orders: OrderWriteRepo, private bus: EventBus) {}

  async handle(cmd: PlaceOrderCommand): Promise<void> {
    const order = Order.create(cmd.customerId, cmd.lines); // enforces invariants
    await this.orders.save(order);                          // normalized write store
    await this.bus.publish(new OrderPlaced({
      orderId: order.id, customerId: cmd.customerId,
      lines: cmd.lines, total: order.total, placedAt: order.placedAt,
    }));
