// Server: issue a presigned POST scoped to one key, size range, and content type.
import { S3Client } from '@aws-sdk/client-s3';
import { createPresignedPost } from '@aws-sdk/s3-presigned-post';
import { randomUUID } from 'crypto';

const s3 = new S3Client({ region: 'eu-west-1' });

export async function createUpload(req, res) {
  const user = req.user; // authenticated
  const { contentType } = req.body;
  if (!/^video\/(mp4|quicktime)$/.test(contentType))
    return res.status(400).json({ error: 'unsupported type' });

  // Server-controlled key — never trust the client's filename.
  const key = `uploads/${user.id}/${randomUUID()}`;

  const presigned = await createPresignedPost(s3, {
    Bucket: 'my-private-bucket',
    Key: key,
    Conditions: [
      ['content-length-range', 1, 2 * 1024 * 1024 * 1024], // 1 byte .. 2 GB cap
      ['eq', '$Content-Type', contentType],
    ],
    Fields: { 'Content-Type': contentType },
    Expires: 60, // URL valid for 60 seconds only
  });

  // Record a PENDING upload; confirmed later by an S3 event notification.
  await db.uploads.insert({ key, userId: user.id, status: 'PENDING' });
  return res.json({ url: presigned.url, fields: presigned.fields, key });
}

