class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.map = new Map();              // key -> node, O(1) lookup
    // sentinel head/tail simplify edge cases (no null checks at the ends)
    this.head = { key: null, val: null, prev: null, next: null }; // MRU side
    this.tail = { key: null, val: null, prev: null, next: null }; // LRU side
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  _remove(node) {                      // unlink a node, O(1)
    node.prev.next = node.next;
    node.next.prev = node.prev;
  }

  _addFront(node) {                    // insert right after head (most recent), O(1)
    node.next = this.head.next;
    node.prev = this.head;
    this.head.next.prev = node;
    this.head.next = node;
  }

  get(key) {
    const node = this.map.get(key);
    if (!node) return -1;
    this._remove(node);                // touch => move to front
    this._addFront(node);
    return node.val;
  }

  put(key, value) {
    const existing = this.map.get(key);
    if (existing) {
      existing.val = value;
      this._remove(existing);
      this._addFront(existing);
      return;
    }
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev;      // node just before tail = least recently used
      this._remove(lru);
      this.map.delete(lru.key);        // evict from map too
    }
    const node = { key, val: value, prev: null, next: null };
    this._addFront(node);
    this.map.set(key, node);
  }
}

// Floyd's Tortoise and Hare — O(n) time, O(1) space.
function hasCycle(head) {
  let slow = head;
  let fast = head;

  while (fast !== null && fast.next !== null) {
    slow = slow.next;        // tortoise: 1 step
    fast = fast.next.next;   // hare: 2 steps
    if (slow === fast) {
      return true;           // they met => a cycle exists
    }
  }
  return false;              // fast fell off the end => no cycle
}

// Bonus: find the cycle's start node once a meeting point is known.
function detectCycleStart(head) {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) {
      // reset one pointer to head; advance both at speed 1; they meet at the entrance.
      let p = head;
      while (p !== slow) { p = p.next; slow = slow.next; }
      return p;
    }
  }
  return null;
}

// Slow: O(n^2) time, O(1) space.
function hasDuplicateSlow(arr) {
  for (let i = 0; i < arr.length; i++) {
    for (let j = i + 1; j < arr.length; j++) {
      if (arr[i] === arr[j]) return true;
    }
  }
  return false;
}

// Fast: O(n) average time, O(n) space — trade memory for speed.
function hasDuplicate(arr) {
  const seen = new Set();
  for (const x of arr) {
    if (seen.has(x)) return true; // O(1) average membership test
    seen.add(x);
  }
  return false;
}

// Space-constrained alternative: O(n log n) time, O(1) extra space (mutates/copies input).
function hasDuplicateSorted(arr) {
  const a = [...arr].sort((x, y) => x - y);
  for (let i = 1; i < a.length; i++) {
    if (a[i] === a[i - 1]) return true; // duplicates are now adjacent
  }
  return false;
}
